exercises.solution_code:
#include <format>
#include <iostream>

int main()
{
    int n{};
    std::cin >> n;

    std::cout << std::format("DEC: {:d}",  n) << '\n';
    std::cout << std::format("BIN: {:#b}", n) << '\n';
    std::cout << std::format("OCT: {:#o}", n) << '\n';
    std::cout << std::format("HEX: {:#X}", n) << '\n';

    return 0;
}

