exercises.solution_code:
#include <format>
#include <iostream>

int main()
{
    constexpr unsigned RED_MASK   = 0xFF'00'00;
    constexpr unsigned GREEN_MASK = 0x00'FF'00;
    constexpr unsigned BLUE_MASK  = 0x00'00'FF;

    unsigned color{};
    std::cin >> color;

    unsigned r = (color & RED_MASK)   >> 16;
    unsigned g = (color & GREEN_MASK) >> 8;
    unsigned b = (color & BLUE_MASK);

    std::cout << std::format("R: {:d} (0b{:b})", r, r) << '\n';
    std::cout << std::format("G: {:d} (0b{:b})", g, g) << '\n';
    std::cout << std::format("B: {:d} (0b{:b})", b, b) << '\n';

    return 0;
}
